@using sv_3ffa4ccd29d84ee18a7f203d43784cdc.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Tasks="filteredTasks" />
    <BoardSearchBar OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetTasksForStatus("To Do")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="id => MoveTask(id, "In Progress")"
                     OnAddTask="data => AddTask(data, "To Do")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetTasksForStatus("In Progress")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, "To Do")"
                     OnMoveRight="id => MoveTask(id, "Done")"
                     OnAddTask="data => AddTask(data, "In Progress")" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetTasksForStatus("Done")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, "In Progress")"
                     OnAddTask="data => AddTask(data, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private List<TaskItem> filteredTasks => string.IsNullOrWhiteSpace(searchText)
        ? allTasks
        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> GetTasksForStatus(string status) =>
        filteredTasks.Where(t => t.Status == status).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // CreateTaskAsync may not set the correct status for the target column
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}
"}

